import cn.dev33.satoken.secure.BCrypt;import java.nio.file.*;import java.sql.*;import java.util.regex.*;
public class MerchantBrowserPrep{
 static final String TEMP_PASSWORD="CodexTemp12!";
 record DbConfig(String url,String username,String password){}
 public static void main(String[]args)throws Exception{DbConfig cfg=readDbConfig();try(Connection c=DriverManager.getConnection(cfg.url(),cfg.username(),cfg.password())){c.setAutoCommit(false);String sql="select u.user_id,u.user_name,u.password from sys_user u join sys_tenant t on t.tenant_id=u.tenant_id join merchant_profile mp on mp.tenant_id=u.tenant_id where t.tenant_type='MERCHANT' and u.del_flag='0' and u.status='1' order by u.create_time desc nulls last limit 1";try(PreparedStatement ps=c.prepareStatement(sql);ResultSet rs=ps.executeQuery()){if(!rs.next())throw new IllegalStateException("No merchant user found");long uid=rs.getLong(1);String name=rs.getString(2);String original=rs.getString(3);Files.writeString(Path.of(".ai/tmp/merchant-browser-restore.dat"),uid+"\n"+original);try(PreparedStatement up=c.prepareStatement("update sys_user set password=? where user_id=?")){up.setString(1,BCrypt.hashpw(TEMP_PASSWORD));up.setLong(2,uid);up.executeUpdate();}c.commit();System.out.println("BROWSER_PREP_OK username="+name);}}}
 static DbConfig readDbConfig()throws Exception{String yml=Files.readString(Path.of("bocoo-admin/src/main/resources/application-dev.yml"));Matcher m=Pattern.compile("url:\\s*(jdbc:postgresql:[^\\r\\n]+).*?username:\\s*([^\\r\\n]+).*?password:\\s*([^\\r\\n]+)",Pattern.DOTALL).matcher(yml);if(!m.find())throw new IllegalStateException("DB config not found");return new DbConfig(m.group(1).trim(),m.group(2).trim(),m.group(3).trim());}
}